function solve(landStartTime: number[], landDuration: number[], waterStartTime: number[], waterDuration: number[]): number {
    let minTime = Infinity;
    const n = landStartTime.length;
    const m = waterStartTime.length;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < m; j++) {
            // Case 1: Land first then Water
            const landStart = landStartTime[i];
            const landEnd = landStart + landDuration[i];
            const waterStart = Math.max(waterStartTime[j], landEnd);
            const waterEnd = waterStart + waterDuration[j];
            const case1 = waterEnd;

            // Case 2: Water first then Land
            const waterStart2 = waterStartTime[j];
            const waterEnd2 = waterStart2 + waterDuration[j];
            const landStart2 = Math.max(landStartTime[i], waterEnd2);
            const landEnd2 = landStart2 + landDuration[i];
            const case2 = landEnd2;

            const currentMin = Math.min(case1, case2);
            if (currentMin < minTime) {
                minTime = currentMin;
            }
        }
    }
    return minTime;
}

